parameters.jsCode:
const raw = $json.output ?? "";

const cleaned = String(raw)
  .replace(/```json/g, "")
  .replace(/```/g, "")
  .trim();

let quiz;

try {
  quiz = JSON.parse(cleaned);

  if (!quiz.questions || !Array.isArray(quiz.questions)) {
    throw new Error("Invalid quiz format");
  }
} catch (error) {
  quiz = {
    title: "Generated Quiz",
    questions: [
      {
        question: "Study Aura generated a quiz response, but it could not be parsed. What should you do?",
        choices: ["Try again", "Close the app", "Delete the workflow", "Ignore the topic"],
        answer: "Try again",
        explanation: "The AI response was not valid JSON, so retrying usually fixes the generated format."
      }
    ]
  };
}

return [
  {
    json: {
      quiz,
      fallback: false
    }
  }
];

